% 1.3 - Plot Displacement vs Time
m  = 5;
k  = 2000;
x0 = 0.02;

wn = sqrt(k/m);
t  = linspace(0, 5, 1000);
x  = x0 * cos(wn * t);

figure(1); %[output:403d90d7]
plot(t, x, 'b-', 'LineWidth', 1.5); %[output:403d90d7]
xlabel('Time (s)'); %[output:403d90d7]
ylabel('Displacement x(t) [m]'); %[output:403d90d7]
title('Undamped Free Vibration — Displacement vs Time'); %[output:403d90d7]
grid on; %[output:403d90d7]

